    private readonly AppDbContext _db;
    public ReportsController(AppDbContext db) => _db = db;

    // GET api/reports/sales-ytd
    [HttpGet("sales-ytd")]
    public async Task<ActionResult<SalesYtdDto>> GetSalesYtd()
    {
        var year = DateTime.UtcNow.Year;
        var yearStart = new DateTime(year, 1, 1);
        var yearEnd = new DateTime(year + 1, 1, 1);

        var total = await _db.OrderDetails
            .Where(od => od.Order!.OrderDate.HasValue &&
                         od.Order.OrderDate >= yearStart &&
                         od.Order.OrderDate < yearEnd)
            .SumAsync(od => (decimal?)(od.Quantity ?? 0) * (od.UnitPrice ?? 0));

        return Ok(new SalesYtdDto { Year = year, TotalRevenue = total ?? 0m });
    }

    // GET api/reports/sales-by-employee
    [HttpGet("sales-by-employee")]
    public async Task<ActionResult<IEnumerable<SalesByEmployeeDto>>> GetSalesByEmployee()
    {
        var year = DateTime.UtcNow.Year;
        var yearStart = new DateTime(year, 1, 1);
        var yearEnd = new DateTime(year + 1, 1, 1);

        var raw = await _db.OrderDetails
            .Where(od => od.Order!.OrderDate.HasValue &&
                         od.Order.OrderDate >= yearStart &&
                         od.Order.OrderDate < yearEnd &&
                         od.Order.EmployeeId.HasValue)
            .Select(od => new
            {
                od.Order!.EmployeeId,
                FirstName = od.Order.Employee != null ? od.Order.Employee.FirstName : null,
                LastName = od.Order.Employee != null ? od.Order.Employee.LastName : null,
                LineTotal = (decimal?)(od.Quantity ?? 0) * (od.UnitPrice ?? 0)
            })
            .ToListAsync();

        var result = raw
            .GroupBy(x => new { x.EmployeeId, x.FirstName, x.LastName })
            .Select(g => new SalesByEmployeeDto
            {
                EmployeeId = g.Key.EmployeeId!.Value,
                EmployeeFullName = $"{g.Key.FirstName} {g.Key.LastName}".Trim(),
                TotalRevenue = g.Sum(x => x.LineTotal ?? 0m)
            })
            .OrderByDescending(x => x.TotalRevenue)
            .ToList();

        return Ok(result);
    }

    // GET api/reports/sales-by-product[?from=&to=]
    [HttpGet("sales-by-product")]
    public async Task<ActionResult<IEnumerable<SalesByProductDto>>> GetSalesByProduct(
        [FromQuery] string? from, [FromQuery] string? to)
    {
        var query = _db.OrderDetails
            .Where(od => od.Order!.OrderDate.HasValue && od.ProductId.HasValue);

        if (!string.IsNullOrEmpty(from) && DateOnly.TryParse(from, out var fromDate))
            query = query.Where(od => od.Order!.OrderDate >= fromDate.ToDateTime(TimeOnly.MinValue));
        if (!string.IsNullOrEmpty(to) && DateOnly.TryParse(to, out var toDate))
            query = query.Where(od => od.Order!.OrderDate <= toDate.ToDateTime(TimeOnly.MaxValue));

        var raw = await query
            .Select(od => new
            {
                od.ProductId,
                ProductName = od.Product != null ? od.Product.ProductName : null,
                Year = od.Order!.OrderDate!.Value.Year,
                Month = od.Order.OrderDate!.Value.Month,
                LineTotal = (decimal?)(od.Quantity ?? 0) * (od.UnitPrice ?? 0)
            })
            .ToListAsync();

        var result = raw
            .GroupBy(x => new { x.ProductId, x.ProductName, x.Year, x.Month })
            .Select(g => new SalesByProductDto
            {
                ProductId = g.Key.ProductId!.Value,
                ProductName = g.Key.ProductName,
                MonthYear = new DateTime(g.Key.Year, g.Key.Month, 1).ToString("MMM-yyyy"),
                MonthYearSort = $"{g.Key.Year:D4}-{g.Key.Month:D2}",
                OrderTotal = g.Sum(x => x.LineTotal ?? 0m)
            })
            .OrderBy(x => x.MonthYearSort).ThenBy(x => x.ProductName)
            .ToList();

        return Ok(result);
    }

    // GET api/reports/sales-by-product-quarterly[?from=&to=]
    [HttpGet("sales-by-product-quarterly")]
    public async Task<ActionResult<IEnumerable<SalesByProductQuarterlyDto>>> GetSalesByProductQuarterly(
        [FromQuery] string? from, [FromQuery] string? to)
    {
        var query = _db.OrderDetails
            .Where(od => od.Order!.OrderDate.HasValue && od.ProductId.HasValue);

        if (!string.IsNullOrEmpty(from) && DateOnly.TryParse(from, out var fromDate))
            query = query.Where(od => od.Order!.OrderDate >= fromDate.ToDateTime(TimeOnly.MinValue));
        if (!string.IsNullOrEmpty(to) && DateOnly.TryParse(to, out var toDate))
            query = query.Where(od => od.Order!.OrderDate <= toDate.ToDateTime(TimeOnly.MaxValue));

        var raw = await query
            .Select(od => new
            {
                od.ProductId,
                ProductName = od.Product != null ? od.Product.ProductName : null,
                Year = od.Order!.OrderDate!.Value.Year,
                Month = od.Order.OrderDate!.Value.Month,
                LineTotal = (decimal?)(od.Quantity ?? 0) * (od.UnitPrice ?? 0)
            })
            .ToListAsync();

        var result = raw
            .GroupBy(x => new { x.ProductId, x.ProductName, x.Year, Quarter = (x.Month - 1) / 3 + 1 })
            .Select(g => new SalesByProductQuarterlyDto
            {
                ProductId = g.Key.ProductId!.Value,
                ProductName = g.Key.ProductName,
                QuarterYear = $"{g.Key.Quarter}-{g.Key.Year}",
                OrderTotal = g.Sum(x => x.LineTotal ?? 0m)
            })
            .OrderBy(x => x.QuarterYear).ThenBy(x => x.ProductName)
            .ToList();

        return Ok(result);
    }

