    // GET api/reports/invoice/{orderId}
    [HttpGet("invoice/{orderId:int}")]
    public async Task<ActionResult<InvoiceDto>> GetInvoice(int orderId)
    {
        var order = await _db.Orders
            .Include(o => o.Customer)
            .Include(o => o.Employee)
            .Include(o => o.Status)
            .Include(o => o.OrderDetails).ThenInclude(od => od.Product)
            .FirstOrDefaultAsync(o => o.OrderId == orderId);

        if (order is null) return NotFound();

        var invoice = new InvoiceDto
        {
            OrderId = order.OrderId,
            OrderDate = order.OrderDate,
            CustomerName = order.Customer?.CustomerName,
            CustomerAddress = order.Customer?.Address,
            CustomerCity = order.Customer?.City,
            CustomerState = order.Customer?.State,
            CustomerZip = order.Customer?.Zip,
            EmployeeFullName = order.Employee != null
                ? $"{order.Employee.FirstName} {order.Employee.LastName}".Trim()
                : null,
            StatusName = order.Status?.StatusName,
            LineItems = order.OrderDetails.Select(od => new InvoiceLineItemDto
            {
                ProductCode = od.Product?.ProductCode,
                ProductName = od.Product?.ProductName,
                Quantity = od.Quantity ?? 0,
                UnitPrice = od.UnitPrice ?? 0m,
                ExtendedPrice = (od.Quantity ?? 0) * (od.UnitPrice ?? 0m)
            }).ToList(),
            OrderTotal = order.OrderDetails.Sum(od => (od.Quantity ?? 0) * (od.UnitPrice ?? 0m))
        };
        return Ok(invoice);
    }

    // GET api/reports/employee-email-list
    [HttpGet("employee-email-list")]
    public async Task<ActionResult<IEnumerable<EmployeeEmailDto>>> GetEmployeeEmailList()
    {
        var result = await _db.Employees
            .OrderBy(e => e.LastName).ThenBy(e => e.FirstName)
            .Select(e => new EmployeeEmailDto
            {
                EmployeeId = e.EmployeeId,
                FullNameLNFN = (e.LastName ?? "") + ", " + (e.FirstName ?? ""),
                EmailAddress = e.EmailAddress
            })
            .ToListAsync();
        return Ok(result);
    }

